zk.start()
stack = [('/', 0)]
seen = set()
while stack:
    path, depth = stack.pop()
    if path in seen or depth > 6:
        continue
    seen.add(path)
    try:
        data, stat = zk.get(path)
    except Exception:
        continue
    decoded = decode(data)
    if decoded and 'FLAG{' in decoded:
        print('FOUND', path)
        print(decoded)
        break
    try:
        children = zk.get_children(path)
    except Exception:
        continue
    for child in children:
        child_path = path + ('/' if path != '/' else '') + child
